import { config, type MetroArea } from "../config.js";
import {
  type PipelineEvent,
    categorizeEvent,
      cleanDescription,
      } from "../normalize.js";
      import { log } from "../utils/logger.js";
      import { delay } from "../utils/geocoder.js";

      // Eventbrite category IDs that are kid/family-friendly
      // https://www.eventbrite.com/platform/api#/reference/category
      const FAMILY_CATEGORY_IDS = [
        "1",   // Music (kids concerts)
          "5",   // Performing & Visual Arts
            "6",   // Film, Media & Entertainment
              "10",  // Sports & Fitness
                "11",  // Health & Wellness
                  "13",  // Community & Culture
                    "14",  // Family & Education
                      "15",  // Science & Technology
                        "16",  // Travel & Outdoor
                          "19",  // Hobbies & Special Interest
                          ];

                          // Keywords used for supplemental searches to catch events not in family category
                          const KID_KEYWORDS = [
                            "kids",
                              "children",
                                "family",
                                  "toddler",
                                    "preschool",
                                    ];

                                    interface EventbriteVenue {
                                      id: string;
                                        name?: string;
                                          address?: {
                                              address_1?: string;
                                                  city?: string;
                                                      region?: string;
                                                          country?: string;
                                                              latitude?: string;
                                                                  longitude?: string;
                                                                    };
                                                                    }

                                                                    interface EventbriteEvent {
                                                                      id: string;
                                                                        name: { text: string; html?: string };
                                                                          description?: { text?: string; html?: string };
                                                                            url: string;
                                                                              start: { local: string; utc: string };
                                                                                end?: { local: string; utc: string };
                                                                                  is_free?: boolean;
                                                                                    ticket_availability?: {
                                                                                        minimum_ticket_price?: { major_value: string; currency: string };
                                                                                            maximum_ticket_price?: { major_value: string; currency: string };
                                                                                              };
                                                                                                logo?: { url: string; original?: { url: string } };
                                                                                                  venue?: EventbriteVenue;
                                                                                                    venue_id?: string;
                                                                                                      category_id?: string;
                                                                                                        subcategory_id?: string;
                                                                                                          tags?: Array<{ tag: string; display_name?: string }>;
                                                                                                            online_event?: boolean;
                                                                                                              status?: string;
                                                                                                              }
                                                                                                              
                                                                                                              interface EventbriteResponse {
                                                                                                                events: EventbriteEvent[];
                                                                                                                  pagination: {
                                                                                                                      page_number: number;
                                                                                                                          page_count: number;
                                                                                                                              has_more_items: boolean;
                                                                                                                                };
                                                                                                                                }
                                                                                                                                
                                                                                                                                export async function fetchEventbriteEvents(
                                                                                                                                  metro: MetroArea
                                                                                                                                  ): Promise<PipelineEvent[]> {
                                                                                                                                    if (!config.eventbrite.apiKey) {
                                                                                                                                        log.warn("eventbrite", "No API key configured, skipping");
                                                                                                                                            return [];
                                                                                                                                              }
                                                                                                                                              
                                                                                                                                                log.info("eventbrite", `Fetching family events for ${metro.name}...`);
                                                                                                                                                
                                                                                                                                                  const seenIds = new Set<string>();
                                                                                                                                                    const events: PipelineEvent[] = [];
                                                                                                                                                    
                                                                                                                                                      // Primary: fetch "Family & Education" category directly
                                                                                                                                                        const familyEvents = await fetchEventbritePage(metro, {
                                                                                                                                                            "categories": "14",
                                                                                                                                                              });
                                                                                                                                                                for (const e of familyEvents) {
                                                                                                                                                                    if (!seenIds.has(e.sourceId)) {
                                                                                                                                                                          seenIds.add(e.sourceId);
                                                                                                                                                                                events.push(e);
                                                                                                                                                                                    }
                                                                                                                                                                                      }
                                                                                                                                                                                      
                                                                                                                                                                                        // Supplemental: keyword searches to catch events in other categories
                                                                                                                                                                                          for (const keyword of KID_KEYWORDS) {
                                                                                                                                                                                              const kwEvents = await fetchEventbritePage(
                                                                                                                                                                                                    metro,
                                                                                                                                                                                                          { q: keyword },
                                                                                                                                                                                                                3 // limit to 3 pages per keyword
                                                                                                                                                                                                                    );
                                                                                                                                                                                                                        for (const e of kwEvents) {
                                                                                                                                                                                                                              if (!seenIds.has(e.sourceId)) {
                                                                                                                                                                                                                                      seenIds.add(e.sourceId);
                                                                                                                                                                                                                                              events.push(e);
                                                                                                                                                                                                                                                    }
                                                                                                                                                                                                                                                        }
                                                                                                                                                                                                                                                          }
                                                                                                                                                                                                                                                          
                                                                                                                                                                                                                                                            log.success(
                                                                                                                                                                                                                                                                "eventbrite",
                                                                                                                                                                                                                                                                    `Found ${events.length} events for ${metro.name}`
                                                                                                                                                                                                                                                                      );
                                                                                                                                                                                                                                                                        return events;
                                                                                                                                                                                                                                                                        }
                                                                                                                                                                                                                                                                        
                                                                                                                                                                                                                                                                        async function fetchEventbritePage(
                                                                                                                                                                                                                                                                          metro: MetroArea,
                                                                                                                                                                                                                                                                            extraParams: Record<string, string>,
                                                                                                                                                                                                                                                                              maxPages = 10
                                                                                                                                                                                                                                                                              ): Promise<PipelineEvent[]> {
                                                                                                                                                                                                                                                                                const events: PipelineEvent[] = [];
                                                                                                                                                                                                                                                                                  let page = 1;
                                                                                                                                                                                                                                                                                    let rateLimitRetries = 0;
                                                                                                                                                                                                                                                                                      const maxRateLimitRetries = 5;
                                                                                                                                                                                                                                                                                      
                                                                                                                                                                                                                                                                                        const now = new Date();
                                                                                                                                                                                                                                                                                          const future = new Date();
                                                                                                                                                                                                                                                                                            future.setDate(future.getDate() + 60);
                                                                                                                                                                                                                                                                                            
                                                                                                                                                                                                                                                                                              while (page <= maxPages) {
                                                                                                                                                                                                                                                                                                  try {
                                                                                                                                                                                                                                                                                                        const params = new URLSearchParams({
                                                                                                                                                                                                                                                                                                                "location.latitude": String(metro.latitude),
                                                                                                                                                                                                                                                                                                                        "location.longitude": String(metro.longitude),
                                                                                                                                                                                                                                                                                                                                "location.within": `${metro.radiusMiles}mi`,
                                                                                                                                                                                                                                                                                                                                        "start_date.range_start": now.toISOString().split(".")[0] + "Z",
                                                                                                                                                                                                                                                                                                                                                "start_date.range_end": future.toISOString().split(".")[0] + "Z",
                                                                                                                                                                                                                                                                                                                                                        "expand": "venue,ticket_availability,category,tags",
                                                                                                                                                                                                                                                                                                                                                                "sort_by": "date",
                                                                                                                                                                                                                                                                                                                                                                        "page": String(page),
                                                                                                                                                                                                                                                                                                                                                                                "page_size": "50",
                                                                                                                                                                                                                                                                                                                                                                                        ...extraParams,
                                                                                                                                                                                                                                                                                                                                                                                              });
                                                                                                                                                                                                                                                                                                                                                                                              
                                                                                                                                                                                                                                                                                                                                                                                                    const url = `${config.eventbrite.baseUrl}/events/search/?${params}`;
                                                                                                                                                                                                                                                                                                                                                                                                          const res = await fetch(url, {
                                                                                                                                                                                                                                                                                                                                                                                                                  headers: {
                                                                                                                                                                                                                                                                                                                                                                                                                            Authorization: `Bearer ${config.eventbrite.apiKey}`,
                                                                                                                                                                                                                                                                                                                                                                                                                                    },
                                                                                                                                                                                                                                                                                                                                                                                                                                          });
                                                                                                                                                                                                                                                                                                                                                                                                                                          
                                                                                                                                                                                                                                                                                                                                                                                                                                                if (res.status === 429) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                        rateLimitRetries++;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                if (rateLimitRetries > maxRateLimitRetries) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                          log.error("eventbrite", "Max rate limit retries exceeded, stopping");
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    break;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    log.warn(
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              "eventbrite",
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        `Rate limited, waiting 2s... (retry ${rateLimitRetries}/${maxRateLimitRetries})`
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                );
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        await delay(2000);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                continue;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            rateLimitRetries = 0;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  if (!res.ok) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          log.error("eventbrite", `HTTP ${res.status}: ${await res.text()}`);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  break;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              const data = (await res.json()) as EventbriteResponse;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    const pageEvents = data.events || [];
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          if (pageEvents.length === 0) break;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                for (const raw of pageEvents) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        const normalized = normalizeEventbriteEvent(raw, metro);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                if (normalized) events.push(normalized);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            if (!data.pagination.has_more_items) break;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  page++;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        // Eventbrite rate limit: ~1000 req/hour => ~1 req/3.6s; use 500ms to be safe
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              await delay(500);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  } catch (err) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        log.error("eventbrite", `Error fetching page ${page}`, err);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              break;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      return events;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      function normalizeEventbriteEvent(
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        raw: EventbriteEvent,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          metro: MetroArea
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          ): PipelineEvent | null {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            // Skip cancelled, draft, or online-only events
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              if (raw.status === "cancelled" || raw.status === "draft") return null;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                if (raw.online_event) return null;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  if (!raw.venue) return null;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    const venue = raw.venue;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      const startDate = raw.start.local;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        const endDate = raw.end?.local;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          if (!startDate) return null;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            // Build price string
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              let price: string | undefined;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                if (raw.is_free) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    price = "Free";
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      } else if (raw.ticket_availability) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          const min = raw.ticket_availability.minimum_ticket_price?.major_value;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              const max = raw.ticket_availability.maximum_ticket_price?.major_value;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  if (min && max && min !== max) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        price = `$${min}-$${max}`;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            } else if (min) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  price = `$${min}`;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          // Build source category tags
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            const sourceTags = (raw.tags || []).map(
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                (t) => t.display_name || t.tag
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  );
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    const title = raw.name.text;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      const description = cleanDescription(raw.description?.text || "");
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        const lat = raw.venue.address?.latitude
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            ? parseFloat(raw.venue.address.latitude)
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                : undefined;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  const lng = raw.venue.address?.longitude
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      ? parseFloat(raw.venue.address.longitude)
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          : undefined;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            return {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                sourceId: `eventbrite:${raw.id}`,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    source: "eventbrite",
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        title,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            description,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                startDate,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    endDate,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        isAllDay: false,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            category: categorizeEvent(title, description, sourceTags),
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                city: venue.address?.city || "",
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    address: venue.address?.address_1,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        latitude: lat,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            longitude: lng,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                locationName: venue.name,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    imageURL: raw.logo?.original?.url || raw.logo?.url,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        externalURL: raw.url,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            websiteURL: raw.url,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                isFeatured: false,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    isRecurring: false,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        tags: sourceTags.filter(Boolean),
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            metro: metro.id,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                price,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  };
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  }
